const editItems: ReadonlyArray<ExampleItem> = [
  { value: 'undo', label: 'Undo', shortcut: '⌘Z' },
  { value: 'redo', label: 'Redo', shortcut: '⇧⌘Z' },
  {
    value: 'find',
    label: 'Find',
    kind: 'submenu-trigger',
